	// VULNERABLE: MD5 is cryptographically broken
	hash := md5.Sum([]byte(input))
	hexHash := fmt.Sprintf("%x", hash)

	w.Header().Set("Content-Type", "application/json")
	fmt.Fprintf(w, `{"algorithm":"md5","input":"%s","hash":"%s"}`, input, hexHash)
}

